// Nhận toàn bộ input
const inputData = $input.all();

// Kiểm tra lỗi hoặc input rỗng
const hasError = inputData.every(item => item.json?.error);
const isEmptyData = inputData.length === 0 || inputData.every(item => Object.keys(item.json || {}).length === 0);

if (hasError || isEmptyData) {
  return {
    json: {
      status: "failed"
    }
  };
}

// Chuyển input thành dữ liệu JSON
let filteredData = inputData.map(item => item.json);

// --- XỬ LÝ FILTER THEO PRODUCT_TYPE ---
const product_type = $('Search_data').first().json.body?.product_type;
let type = [];
let skipTypeFilter = false;

try {
  if (typeof product_type === 'string') {
    const trimmed = product_type.trim();
    if (trimmed.toLowerCase() === 'none') {
      skipTypeFilter = true;
    } else if (trimmed.startsWith('[')) {
      const jsonStr = trimmed.replace(/'/g, '"');
      const parsed = JSON.parse(jsonStr);
      if (Array.isArray(parsed)) {
        type = parsed.map(i => i.trim().toLowerCase());
      }
    } else if (trimmed !== '') {
      type = [trimmed.toLowerCase()];
    }
  } else if (Array.isArray(product_type)) {
    type = product_type.map(i => i.trim().toLowerCase());
  }
} catch (e) {
  type = [];
}

if (!skipTypeFilter && type.length > 0) {
  filteredData = filteredData.filter(item =>
    typeof item.type === 'string' &&
    type.includes(item.type.trim().toLowerCase())
  );
}

// --- XỬ LÝ FILTER THEO VENDOR ---
const vendorInput = $('Search_data').first().json.body?.vendor;
let vendors = [];
let skipVendorFilter = false;

try {
  if (typeof vendorInput === 'string') {
    const trimmed = vendorInput.trim();
    if (trimmed.toLowerCase() === 'none') {
      skipVendorFilter = true;
    } else if (trimmed.startsWith('[')) {
      const jsonStr = trimmed.replace(/'/g, '"');
      const parsed = JSON.parse(jsonStr);
      if (Array.isArray(parsed)) {
        vendors = parsed.map(i => i.trim().toLowerCase());
      }
    } else if (trimmed !== '') {
      vendors = [trimmed.toLowerCase()];
    }
  } else if (Array.isArray(vendorInput)) {
    vendors = vendorInput.map(i => i.trim().toLowerCase());
  }
} catch (e) {
  vendors = [];
}

if (!skipVendorFilter && vendors.length > 0) {
  filteredData = filteredData.filter(item =>
    typeof item.vendor === 'string' &&
    vendors.includes(item.vendor.trim().toLowerCase())
  );
}

// --- TRẢ KẾT QUẢ CUỐI CÙNG ---
if (filteredData.length === 0) {
  return {
    json: {
      status: "failed"
    }
  };
}

return {
  json: {
    status: "success",
    data: filteredData
  }
};
